import {
  BrowserRouter as Router,
  Routes,
  Route,
  Navigate,
} from "react-router-dom";

import LoginPage from "./pages/auth/LoginPage";
import RegisterPage from "./pages/auth/RegisterPage";
import OAuthCallback from "./pages/auth/OAuthCallback";

import AdminDashboard from "./pages/admin/AdminDashboard";
import UsersPage from "./pages/admin/UsersPage";

import PrivateRoute from "./routes/PrivateRoute";

function App() {

  return (

    <Router>

      <Routes>

        <Route path="/" element={<Navigate to="/login" />} />

        <Route path="/login" element={<LoginPage />} />

        <Route path="/register" element={<RegisterPage />} />

        <Route path="/oauth-callback" element={<OAuthCallback />} />

        <Route
          path="/admin"
          element={
            <PrivateRoute>
              <AdminDashboard />
            </PrivateRoute>
          }
        />

        <Route
          path="/admin/users"
          element={
            <PrivateRoute>
              <UsersPage />
            </PrivateRoute>
          }
        />




        {/* CLIENT */}
<Route
          path="/client"
          element={
            <ClientLayout>
              <Dashboard />
            </ClientLayout>
          }
        />

        <Route
          path="/client/create"
          element={
            <ClientLayout>
              <CreateOrder />
            </ClientLayout>
          }
        />

        <Route
          path="/client/orders"
          element={
            <ClientLayout>
              <OrdersHistory />
            </ClientLayout>
          }
        />

        <Route
          path="/client/track"
          element={
            <ClientLayout>
              <OrderTracking />
            </ClientLayout>
          }
        />

        <Route
          path="/client/notifications"
          element={
            <ClientLayout>
              <Notifications />
            </ClientLayout>
          }
        />

        {/* CLIENT */}
      </Routes>

    </Router>

  );

}

export default App;
